// main-sub.bicep — deployed at subscription scope
targetScope = 'subscription'

param location string = 'eastus'
param tags object = {
  environment: 'production'
  managed-by: 'platform'
}

// Create a resource group — only possible at subscription scope
resource rg 'Microsoft.Resources/resourceGroups@2023-07-01' = {
  name: 'rg-payments-prod'
  location: location
  tags: tags
}

// Assign a policy at subscription scope
resource policyAssignment 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'sub-require-tags'
  properties: {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/1e30110a-5ceb-460c-a204-c1c3969c6d62'
    parameters: {
      tagName: { value: 'environment' }
    }
  }
}

// Deploy a module into the resource group just created
module storageModule './storage.bicep' = {
  name: 'storage-deploy'
  scope: rg   // <-- explicit scope: the RG created above
  params: {
    location: location
  }
}

// main-mg.bicep — deployed at management group scope
targetScope = 'managementGroup'

// Create a child management group
resource childMg 'Microsoft.Management/managementGroups@2021-04-01' = {
  name: 'mg-corp-prod'
  properties: {
    displayName: 'Corp - Production'
    details: {
      parent: {
        id: '/providers/Microsoft.Management/managementGroups/mg-corp'
      }
    }
  }
}

// Assign a policy at MG scope
resource corpProdPolicy 'Microsoft.Authorization/policyAssignments@2022-06-01' = {
  name: 'deny-vm-public-ip'
  properties: {
    policyDefinitionId: '/providers/Microsoft.Authorization/policyDefinitions/65523614-dabb-4b52-a6ef-5c7e235b3a74'
    enforcementMode: 'Default'
  }
}

# Retrieve references at each scope level

# Management group scope
data "azurerm_management_group" "corp" {
  name = "mg-corp"
}

# Subscription scope
data "azurerm_subscription" "current" {}

# Resource group scope
data "azurerm_resource_group" "payments" {
  name = "rg-payments-prod"
}

# Assign RBAC at each scope level using the scoped resource ID
resource "azurerm_role_assignment" "mg_reader" {
  scope                = data.azurerm_management_group.corp.id
  role_definition_name = "Reader"
  principal_id         = var.platform_team_group_id
}

resource "azurerm_role_assignment" "sub_contributor" {
  scope                = data.azurerm_subscription.current.id
  role_definition_name = "Contributor"
  principal_id         = var.app_team_group_id
}

resource "azurerm_role_assignment" "rg_contributor" {
  scope                = data.azurerm_resource_group.payments.id
  role_definition_name = "Contributor"
  principal_id         = var.cicd_sp_object_id
}

# Assign policy at management group scope
resource "azurerm_management_group_policy_assignment" "require_tags" {
  name                 = "require-env-tag"
  management_group_id  = data.azurerm_management_group.corp.id
  policy_definition_id = var.require_tag_policy_id
  parameters = jsonencode({
    tagName = { value = "environment" }
  })
}

# Assign policy at subscription scope
resource "azurerm_subscription_policy_assignment" "allowed_skus" {
  name                 = "allowed-vm-skus"
  subscription_id      = data.azurerm_subscription.current.id
  policy_definition_id = var.allowed_skus_policy_id
  parameters = jsonencode({
    listOfAllowedSKUs = { value = ["Standard_D2s_v5", "Standard_D4s_v5"] }
  })
}

# Assign policy at resource group scope
resource "azurerm_resource_group_policy_assignment" "allowed_locs" {
  name                 = "rg-allowed-locs"
  resource_group_id    = data.azurerm_resource_group.payments.id
  policy_definition_id = var.allowed_locations_policy_id
  parameters = jsonencode({
    listOfAllowedLocations = { value = ["eastus", "eastus2"] }
  })
}
